        )
) AS v(
    "id",
    "upcGtin",
    "mop",
    "map",
    "msrp",
    "quantityPerCarton",
    "orderByDate",
    "editingStatus",
    "description",
    "imageLink",
    "stockCount"
)
WHERE p."id" = v."id"
  AND p."sku" LIKE 'MOCK-SKU-%';

